(window.webpackJsonp=window.webpackJsonp||[]).push([[43],{449:function(a,v,t){"use strict";t.r(v);var e=t(34),r=Object(e.a)({},(function(){var a=this,v=a.$createElement,t=a._self._c||v;return t("ContentSlotsDistributor",{attrs:{"slot-key":a.$parent.slotKey}},[t("h1",{attrs:{id:"简介"}},[t("a",{staticClass:"header-anchor",attrs:{href:"#简介"}},[a._v("#")]),a._v(" 简介")]),a._v(" "),t("h2",{attrs:{id:"js是什么"}},[t("a",{staticClass:"header-anchor",attrs:{href:"#js是什么"}},[a._v("#")]),a._v(" JS是什么")]),a._v(" "),t("p",[a._v("JavaScript 是一种轻量级的脚本语言。所谓“脚本语言”（script language），指的是它不具备开发操作系统的能力，而是只用来编写控制其他大型应用程序（比如浏览器）的“脚本”。")]),a._v(" "),t("p",[a._v("JavaScript 也是一种嵌入式（embedded）语言。它本身提供的核心语法不算很多，只能用来做一些数学和逻辑运算。JavaScript 本身不提供任何与 I/O（输入/输出）相关的 API，都要靠宿主环境（host）提供，所以 JavaScript 只合适嵌入更大型的应用程序环境，去调用宿主环境提供的底层 API。")]),a._v(" "),t("p",[a._v("目前，已经嵌入 JavaScript 的宿主环境有多种，最常见的环境就是浏览器，另外还有服务器环境，也就是 Node 项目。")]),a._v(" "),t("p",[a._v("从语法角度看，JavaScript 语言是一种“对象模型”语言。各种宿主环境通过这个模型，描述自己的功能和操作接口，从而通过 JavaScript 控制这些功能。但是，JavaScript 并不是纯粹的“面向对象语言”，还支持其他编程范式（比如函数式编程）。这导致几乎任何一个问题，JavaScript 都有多种解决方法。阅读本书的过程中，你会诧异于 JavaScript 语法的灵活性。")]),a._v(" "),t("p",[a._v("JavaScript 的核心语法部分相当精简，只包括两个部分：基本的语法构造（比如操作符、控制结构、语句）和标准库（就是一系列具有各种功能的对象比如Array、Date、Math等）。除此之外，各种宿主环境提供额外的 API（即只能在该环境使用的接口），以便 JavaScript 调用。以浏览器为例，它提供的额外 API 可以分成三大类。")]),a._v(" "),t("ul",[t("li",[a._v("浏览器控制类：操作浏览器")]),a._v(" "),t("li",[a._v("DOM 类：操作网页的各种元素")]),a._v(" "),t("li",[a._v("Web 类：实现互联网的各种功能")])]),a._v(" "),t("p",[a._v("如果宿主环境是服务器，则会提供各种操作系统的 API，比如文件操作 API、网络通信 API等等。这些你都可以在 Node 环境中找到。")]),a._v(" "),t("p",[a._v("本书主要介绍 JavaScript 核心语法和浏览器网页开发的基本知识，不涉及 Node。全书可以分成以下四大部分。")]),a._v(" "),t("ul",[t("li",[a._v("基本语法")]),a._v(" "),t("li",[a._v("标准库")]),a._v(" "),t("li",[a._v("浏览器 API")]),a._v(" "),t("li",[a._v("DOM")])]),a._v(" "),t("h2",{attrs:{id:"js发展史"}},[t("a",{staticClass:"header-anchor",attrs:{href:"#js发展史"}},[a._v("#")]),a._v(" JS发展史")]),a._v(" "),t("p",[a._v("JavaScript 因为互联网而生，紧跟着浏览器的出现而问世。回顾它的历史，就要从浏览器的历史讲起。")]),a._v(" "),t("p",[a._v("1990年底，欧洲核能研究组织（CERN）科学家 Tim Berners-Lee，在全世界最大的电脑网络——互联网的基础上，发明了万维网（World Wide Web），从此可以在网上浏览网页文件。最早的网页只能在操作系统的终端里浏览，也就是说只能使用命令行操作，网页都是在字符窗口中显示，这当然非常不方便。")]),a._v(" "),t("p",[a._v("1992年底，美国国家超级电脑应用中心（NCSA）开始开发一个独立的浏览器，叫做 Mosaic。这是人类历史上第一个浏览器，从此网页可以在图形界面的窗口浏览。")]),a._v(" "),t("p",[a._v("1994年10月，NCSA 的一个主要程序员 Marc Andreessen 联合风险投资家 Jim Clark，成立了 Mosaic 通信公司（Mosaic Communications），不久后改名为 Netscape。这家公司的方向，就是在 Mosaic 的基础上，开发面向普通用户的新一代的浏览器 Netscape Navigator。")]),a._v(" "),t("p",[a._v("1994年12月，Navigator 发布了1.0版，市场份额一举超过90%。")]),a._v(" "),t("p",[a._v("Netscape 公司很快发现，Navigator 浏览器需要一种可以嵌入网页的脚本语言，用来控制浏览器行为。当时，网速很慢而且上网费很贵，有些操作不宜在服务器端完成。比如，如果用户忘记填写“用户名”，就点了“发送”按钮，到服务器再发现这一点就有点太晚了，最好能在用户发出数据之前，就告诉用户“请填写用户名”。这就需要在网页中嵌入小程序，让浏览器检查每一栏是否都填写了。")]),a._v(" "),t("p",[a._v("管理层对这种浏览器脚本语言的设想是：功能不需要太强，语法较为简单，容易学习和部署。那一年，正逢 Sun 公司的 Java 语言问世，市场推广活动非常成功。Netscape 公司决定与 Sun 公司合作，浏览器支持嵌入 Java 小程序（后来称为 Java applet）。但是，浏览器脚本语言是否就选用 Java，则存在争论。后来，还是决定不使用 Java，因为网页小程序不需要 Java 这么“重”的语法。但是，同时也决定脚本语言的语法要接近 Java，并且可以支持 Java 程序。这些设想直接排除了使用现存语言，比如 Perl、Python 和 TCL。")]),a._v(" "),t("p",[a._v("1995年，Netscape 公司雇佣了程序员 Brendan Eich 开发这种网页脚本语言。Brendan Eich 有很强的函数式编程背景，希望以 Scheme 语言（函数式语言鼻祖 LISP 语言的一种方言）为蓝本，实现这种新语言。")]),a._v(" "),t("p",[a._v("1995年5月，Brendan Eich 只用了10天，就设计完成了这种语言的第一版。它是一个大杂烩，语法有多个来源。")]),a._v(" "),t("ul",[t("li",[a._v("基本语法：借鉴 C 语言和 Java 语言。")]),a._v(" "),t("li",[a._v("数据结构：借鉴 Java 语言，包括将值分成原始值和对象两大类。")]),a._v(" "),t("li",[a._v("函数的用法：借鉴 Scheme 语言和 Awk 语言，将函数当作第一等公民，并引入闭包。")]),a._v(" "),t("li",[a._v("原型继承模型：借鉴 Self 语言（Smalltalk 的一种变种）。")]),a._v(" "),t("li",[a._v("正则表达式：借鉴 Perl 语言。")]),a._v(" "),t("li",[a._v("字符串和数组处理：借鉴 Python 语言。")])]),a._v(" "),t("p",[a._v("为了保持简单，这种脚本语言缺少一些关键的功能，比如块级作用域、模块、子类型（subtyping）等等，但是可以利用现有功能找出解决办法。这种功能的不足，直接导致了后来 JavaScript 的一个显著特点：对于其他语言，你需要学习语言的各种功能，而对于 JavaScript，你常常需要学习各种解决问题的模式。而且由于来源多样，从一开始就注定，JavaScript 的编程风格是函数式编程和面向对象编程的一种混合体。")]),a._v(" "),t("p",[a._v("Netscape 公司的这种浏览器脚本语言，最初名字叫做 Mocha，1995年9月改为 LiveScript。12月，Netscape 公司与 Sun 公司（Java 语言的发明者和所有者）达成协议，后者允许将这种语言叫做 JavaScript。这样一来，Netscape 公司可以借助 Java 语言的声势，而 Sun 公司则将自己的影响力扩展到了浏览器。")]),a._v(" "),t("p",[a._v("之所以起这个名字，并不是因为 JavaScript 本身与 Java 语言有多么深的关系（事实上，两者关系并不深，详见下节），而是因为 Netscape 公司已经决定，使用 Java 语言开发网络应用程序，JavaScript 可以像胶水一样，将各个部分连接起来。当然，后来的历史是 Java 语言的浏览器插件失败了，JavaScript 反而发扬光大。")]),a._v(" "),t("p",[a._v("1995年12月4日，Netscape 公司与 Sun 公司联合发布了 JavaScript 语言，对外宣传 JavaScript 是 Java 的补充，属于轻量级的 Java，专门用来操作网页。")]),a._v(" "),t("p",[a._v("1996年3月，Navigator 2.0 浏览器正式内置了 JavaScript 脚本语言。")]),a._v(" "),t("h2",{attrs:{id:"js热门书籍和权威网站"}},[t("a",{staticClass:"header-anchor",attrs:{href:"#js热门书籍和权威网站"}},[a._v("#")]),a._v(" JS热门书籍和权威网站")]),a._v(" "),t("p",[t("strong",[a._v("JavaScript")])]),a._v(" "),t("p",[t("a",{attrs:{href:"https://wangdoc.com/javascript/index.html",target:"_blank",rel:"noopener noreferrer"}},[a._v("https://wangdoc.com/javascript/index.html"),t("OutboundLink")],1)]),a._v(" "),t("p",[t("a",{attrs:{href:"https://developer.mozilla.org/zh-CN/docs/Web/JavaScript/Reference/Global_Objects/Object/getOwnPropertyNames",target:"_blank",rel:"noopener noreferrer"}},[a._v("https://developer.mozilla.org/zh-CN/docs/Web/JavaScript/Reference/Global_Objects/Object/getOwnPropertyNames"),t("OutboundLink")],1)]),a._v(" "),t("p",[t("strong",[a._v("ES6")])]),a._v(" "),t("p",[t("a",{attrs:{href:"https://es6.ruanyifeng.com/",target:"_blank",rel:"noopener noreferrer"}},[a._v("https://es6.ruanyifeng.com/"),t("OutboundLink")],1)])])}),[],!1,null,null,null);v.default=r.exports}}]);